import heapq
class Solution:
    def leastOpsExpressTarget(self, x, target):
        terms = []
        p = 1
        k = 0
        while p <= 2 * target:
            terms.append((p, 1 if k == 0 else k - 1))
            p *= x
            k += 1
        LO, HI = -target, 2 * target
        best = {}
        pq = [(bc, v) for (v, bc) in terms]
        heapq.heapify(pq)
        while pq:
            c, val = heapq.heappop(pq)
            if val == target:
                return c
            if val in best and best[val] <= c:
                continue
            best[val] = c
            if c > 80:
                continue
            for v, bc in terms:
                for sign in (1, -1):
                    nv = val + sign * v
                    if nv < LO or nv > HI:
                        continue
                    nc = c + 1 + bc
                    if nv not in best or best[nv] > nc:
                        heapq.heappush(pq, (nc, nv))
        return -1

