class Solution:
    def leastOpsExpressTarget(self, x, target):
        from functools import lru_cache
        @lru_cache(maxsize=None)
        def dp(t, k):
            if t == 0:
                return 0
            if k > 40:
                return float('inf')
            unit = 2 if k == 0 else k
            q, r = divmod(t, x)
            below = r * unit + dp(q, k + 1)
            above = float('inf')
            if r != 0:
                above = (x - r) * unit + dp(q + 1, k + 1)
            return min(below, above)
        return dp(target, 0) - 1

