var leastOpsExpressTarget = function(x, target) {
    const memo = new Map();
    const dp = (t, k) => {
        if (t === 0) return 0;
        if (k > 40) return Infinity;
        const key = t + ':' + k;
        if (memo.has(key)) return memo.get(key);
        const unit = k === 0 ? 2 : k;
        const q = Math.floor(t / x);
        const r = t - q * x;
        let below = r * unit + dp(q, k + 1);
        let above = Infinity;
        if (r !== 0) above = (x - r) * unit + dp(q + 1, k + 1);
        const res = Math.min(below, above);
        memo.set(key, res);
        return res;
    };
    return dp(target, 0) - 1;
};
